CREATE OR REPLACE FUNCTION api.safe_numeric(value text) RETURNS numeric LANGUAGE sql IMMUTABLE AS $$ SELECT CASE WHEN value IS NULL OR btrim(value) = '' THEN NULL WHEN btrim(value) ~ '^-?[0-9]+([.,][0-9]+)?$' THEN replace(btrim(value), ',', '.')::numeric ELSE NULL END $$;
CREATE OR REPLACE FUNCTION api.safe_bigint(value text) RETURNS bigint LANGUAGE sql IMMUTABLE AS $$ SELECT CASE WHEN value IS NULL OR btrim(value) = '' THEN NULL WHEN btrim(value) ~ '^-?[0-9]+$' THEN btrim(value)::bigint ELSE NULL END $$;
CREATE OR REPLACE FUNCTION api.safe_timestamptz(value text) RETURNS timestamptz LANGUAGE plpgsql IMMUTABLE AS $$ BEGIN IF value IS NULL OR btrim(value) = '' THEN RETURN NULL; END IF; IF btrim(value) ~ '^[0-9]{10}$' THEN RETURN to_timestamp(btrim(value)::bigint); END IF; IF btrim(value) ~ '^[0-9]{13}$' THEN RETURN to_timestamp((btrim(value)::numeric / 1000)); END IF; RETURN NULLIF(value, '')::timestamptz; EXCEPTION WHEN others THEN RETURN NULL; END $$;
CREATE OR REPLACE FUNCTION api.animal_profile_url(handle text, animal_id bigint) RETURNS text LANGUAGE sql IMMUTABLE AS $$ SELECT CASE WHEN NULLIF(btrim(handle), '') IS NULL OR animal_id IS NULL THEN '' ELSE 'https://www.thehunter.com/#profile/' || btrim(handle) || '/score/' || animal_id::text END $$;
CREATE OR REPLACE FUNCTION api.medal_icon_url(rank_no bigint) RETURNS text LANGUAGE sql IMMUTABLE AS $$ SELECT CASE rank_no WHEN 1 THEN 'data:image/png;base64,' WHEN 2 THEN 'data:image/png;base64,' WHEN 3 THEN 'data:image/png;base64,' ELSE '' END $$;
CREATE OR REPLACE FUNCTION api.species_icon_url(value text) RETURNS text LANGUAGE sql IMMUTABLE AS $$ SELECT CASE WHEN value IS NULL THEN 'https://static.wikia.nocookie.net/thehunter/images/9/9a/Reindeer_male_common.png/revision/latest/scale-to-width-down/60?cb=20240428082331&path-prefix=es' WHEN lower(value) LIKE '%alpine ibex%' THEN 'https://static.wikia.nocookie.net/thehunter/images/5/5b/Alpine_ibex_male_common.png/revision/latest/scale-to-width-down/60?cb=20240428082330&path-prefix=es' WHEN lower(value) LIKE '%american black duck%' THEN 'https://static.wikia.nocookie.net/thehunter/images/2/2b/American_black_duck_male_common.png/revision/latest/scale-to-width-down/60?cb=20240428164606&path-prefix=es' WHEN lower(value) LIKE '%arctic fox%' THEN 'https://static.wikia.nocookie.net/thehunter/images/b/bb/Arctic_fox_male_common.png/revision/latest/scale-to-width-down/60?cb=20240428082331&path-prefix=es' WHEN lower(value) LIKE '%axis deer%' THEN 'https://static.wikia.nocookie.net/thehunter/images/e/ed/Axis_deer_male_common.png/revision/latest/scale-to-width-down/60?cb=20240428082329&path-prefix=es' WHEN lower(value) LIKE '%banteng%' THEN 'https://static.wikia.nocookie.net/thehunter/images/b/b1/Banteng_male_common.png/revision/latest/scale-to-width-down/60?cb=20240428082330&path-prefix=es' WHEN lower(value) LIKE '%bighorn sheep%' THEN 'https://static.wikia.nocookie.net/thehunter/images/d/de/Bighorn_sheep_male_common.png/revision/latest/scale-to-width-down/60?cb=20240428082329&path-prefix=es' WHEN lower(value) LIKE '%bison%' THEN 'https://static.wikia.nocookie.net/thehunter/images/c/cd/Bison_male_common.png/revision/latest/scale-to-width-down/60?cb=20240428082329&path-prefix=es' WHEN lower(value) LIKE '%black bear%' THEN 'https://static.wikia.nocookie.net/thehunter/images/1/10/Black_bear_male_common.png/revision/latest/scale-to-width-down/60?cb=20240428082329&path-prefix=es' WHEN lower(value) LIKE '%blacktail deer%' THEN 'https://static.wikia.nocookie.net/thehunter/images/