.net/thehunter/images/d/dc/Roe_deer_male_common.png/revision/latest/scale-to-width-down/60?cb=20240428082331&path-prefix=es' WHEN lower(value) LIKE '%roosevelt elk%' THEN 'https://static.wikia.nocookie.net/thehunter/images/b/b6/Roosevelt_elk_male_common.png/revision/latest/scale-to-width-down/60?cb=20240428164249&path-prefix=es' WHEN lower(value) LIKE '%rusa deer%' THEN 'https://static.wikia.nocookie.net/thehunter/images/c/cc/Rusa_deer_male_common.png/revision/latest/scale-to-width-down/60?cb=20240428082331&path-prefix=es' WHEN lower(value) LIKE '%sambar deer%' THEN 'https://static.wikia.nocookie.net/thehunter/images/d/dc/Sambar_deer_male_common.png/revision/latest/scale-to-width-down/60?cb=20240428082331&path-prefix=es' WHEN lower(value) LIKE '%sitka deer%' THEN 'https://static.wikia.nocookie.net/thehunter/images/a/a4/Sitka_deer_male_common.png/revision/latest/scale-to-width-down/60?cb=20240428082330&path-prefix=es' WHEN lower(value) LIKE '%snow goose%' THEN 'https://static.wikia.nocookie.net/thehunter/images/5/59/Snow_goose_male_common.png/revision/latest/scale-to-width-down/60?cb=20240428082331&path-prefix=es' WHEN lower(value) LIKE '%snowshoe hare%' THEN 'https://static.wikia.nocookie.net/thehunter/images/f/f7/Snowshoe_hare_male_common.png/revision/latest/scale-to-width-down/60?cb=20240428082331&path-prefix=es' WHEN lower(value) LIKE '%turkey%' THEN 'https://static.wikia.nocookie.net/thehunter/images/f/f2/Turkey_male_common.png/revision/latest/scale-to-width-down/60?cb=20240428082331&path-prefix=es' WHEN lower(value) LIKE '%water buffalo%' THEN 'https://static.wikia.nocookie.net/thehunter/images/c/c9/Water_buffalo_male_common.png/revision/latest/scale-to-width-down/60?cb=20240428155359&path-prefix=es' WHEN lower(value) LIKE '%whitetail deer%' THEN 'https://static.wikia.nocookie.net/thehunter/images/0/0b/Whitetail_deer_male_common.png/revision/latest/scale-to-width-down/60?cb=20240428082331&path-prefix=es' WHEN lower(value) LIKE '%wild boar%' THEN 'https://static