DROP VIEW IF EXISTS api.vw_hunter_overview CASCADE;
CREATE VIEW api.vw_hunter_overview AS SELECT u.record_id AS hunter_record_id, u.field_id AS user_id, u.field_hostname AS hostname, u.field_handle AS handle, u.field_avatar AS avatar_url, api.safe_numeric(u.field_hunterscore) AS hunter_score, api.safe_bigint(u.field_rank) AS rank_no, u.field_membership AS membership, u.field_online AS online_status, api.safe_numeric(u.field_stats_field_distance) AS profile_distance, api.safe_numeric(u.field_stats_field_duration) AS profile_duration, api.safe_numeric(l.field_distance) AS lifetime_distance, api.safe_numeric(l.field_duration) AS lifetime_duration, CASE WHEN api.safe_numeric(l.field_duration) IS NOT NULL THEN api.safe_numeric(l.field_duration) / 3600 END AS lifetime_hours, CASE WHEN api.safe_numeric(l.field_distance) IS NOT NULL THEN api.safe_numeric(l.field_distance) / 1000 END AS lifetime_km, (SELECT COALESCE(SUM(api.safe_bigint(a.field_kills)), 0) FROM api.query_statistics_lifetime_animal a) AS lifetime_kills, (SELECT COALESCE(SUM(api.safe_bigint(a.field_ethical_kills)), 0) FROM api.query_statistics_lifetime_animal a) AS lifetime_ethical_kills, (SELECT COALESCE(SUM(api.safe_bigint(a.field_spots)), 0) FROM api.query_statistics_lifetime_animal a) AS lifetime_spots, (SELECT COALESCE(SUM(api.safe_bigint(a.field_tracks)), 0) FROM api.query_statistics_lifetime_animal a) AS lifetime_tracks FROM api.query_user_by_hostname u LEFT JOIN api.query_statistics_lifetime l ON true ORDER BY u.record_id;
DROP VIEW IF EXISTS api.vw_weapon_analytics CASCADE;
CREATE VIEW api.vw_weapon_analytics AS SELECT w.weapon_id, COALESCE(NULLIF(ci.field_name, ''), NULLIF(ci.field_shortname, ''), 'Weapon ' || w.weapon_id::text) AS weapon_name, NULLIF(ci.field_type, '') AS weapon_type, SUM(COALESCE(w.hits, 0)) AS hits, SUM(COALESCE(w.kills, 0)) AS kills, SUM(COALESCE(w.misses, 0)) AS misses, SUM(COALESCE(w.ethical_kills, 0)) AS ethical_kills, SUM(COALESCE(w.distance, 0)) AS distance_total, CASE WHEN SUM(COALESCE(w.hits, 0) + COALESCE(w.misses, 0)) > 0 THEN ROUND(SUM(COALESCE(w.hits, 0))::numeric / SUM(COALESCE(w.hits, 0) + COALESCE(w.misses, 0))::numeric * 100, 2) END AS accuracy_pct, CASE WHEN SUM(COALESCE(w.kills, 0)) > 0 THEN ROUND(SUM(COALESCE(w.ethical_kills, 0))::numeric / SUM(COALESCE(w.kills, 0))::numeric * 100, 2) END AS ethical_pct, CASE WHEN SUM(COALESCE(w.hits, 0)) > 0 THEN ROUND(SUM(COALESCE(w.kills, 0))::numeric / SUM(COALESCE(w.hits, 0))::numeric * 100, 2) END AS lethality_pct, CASE WHEN SUM(COALESCE(w.kills, 0)) > 0 THEN ROUND(SUM(COALESCE(w.distance, 0))::numeric / SUM(COALESCE(w.kills, 0))::numeric, 2) END AS avg_distance_per_kill, ROUND(SUM(COALESCE(w.kills, 0))::numeric / NULLIF((SELECT SUM(COALESCE(kills, 0)) FROM api.query_statistics_lifetime_weapon_stats), 0) * 100, 2) AS usage_kill_share_pct FROM api.query_statistics_lifetime_weapon_stats w LEFT JOIN api.query_catalog_items ci ON api.safe_bigint(ci.field_id) = w.weapon_id GROUP BY w.weapon_id, COALESCE(NULLIF(ci.field_name, ''), NULLIF(ci.field_shortname, ''), 'Weapon ' || w.weapon_id::text), NULLIF(ci.field_type, '');
DROP VIEW IF EXISTS api.vw_species_analytics CASCADE;
CREATE VIEW api.vw_species_analytics AS SELECT api.safe_bigint(a.item_key) AS species_id, COALESCE(NULLIF(s.field_name, ''), 'Species ID ' || a.item_key) AS species_name, SUM(COALESCE(api.safe_bigint(a.field_kills), 0)) AS kills, SUM(COALESCE(api.safe_bigint(a.field_ethical_kills), 0)) AS ethical_kills, SUM(COALESCE(api.safe_bigint(a.field_spots), 0)) AS spots, SUM(COALESCE(api.safe_bigint(a.field_tracks), 0)) AS tracks, CASE WHEN SUM(COALESCE(api.safe_bigint(a.field_kills), 0)) > 0 THEN ROUND(SUM(COALESCE(api.safe_bigint(a.field_ethical_kills), 0))::numeric / SUM(COALESCE(api.safe_bigint(a.field_kills), 0))::numeric * 100, 2) END AS ethical_pct, CASE WHEN SUM(COALESCE(api.safe_bigint(a.field_kills), 0)) > 0 THEN ROUND(SUM(COALESCE(api.safe_bigint(a.field_tracks), 0))::numeric / SUM(COALESCE(api.safe_bigint(a.field_kills), 0))::numeric, 2) END AS tracks_per_kill, CASE WHEN SUM(COALESCE(api.safe_bigint(a.field_kills), 0)) > 0 THEN ROUND(SUM(COALESCE(api.safe_bigint(a.field_spots), 0))::numeric / SUM(COALESCE(api.safe_bigint(a.field_kills), 0))::numeric, 2) END AS spots_per_kill, ROUND(SUM(COALESCE(api.safe_bigint(a.field_kills), 0))::numeric / NULLIF((SELECT SUM(COALESCE(api.safe_bigint(x.field_kills), 0)) FROM api.query_statistics_lifetime_animal x), 0) * 100, 2) AS kill_share_pct FROM api.query_statistics_lifetime_animal a LEFT JOIN api.query_catalog_species s ON api.safe_bigint(s.field_id) = api.safe_bigint(a.item_key) GROUP BY api.safe_bigint(a.item_key), COALESCE(NULLIF(s.field_name, ''), 'Species ID ' || a.item_key);
DROP VIEW IF EXISTS api.vw_expedition_monthly CASCADE;
DROP VIEW IF EXISTS api.vw_expedition_weekly CASCADE;
CREATE VIEW api.vw_expedition_weekly AS SELECT date_trunc('week', api.safe_timestamptz(e.field_start_ts))::date AS week_start, COUNT(*) AS expeditions, SUM(COALESCE(api.safe_bigint(e.field_kills), 0)) AS kills, SUM(COALESCE(api.safe_bigint(e.field_collectables), 0)) AS collectables, SUM(EXTRACT(EPOCH FROM (api.safe_timestamptz(e.field_end_ts) - api.safe_timestamptz(e.field_start_ts)))) AS duration_seconds, ROUND(SUM(EXTRACT(EPOCH FROM (api.safe_timestamptz(e.field_end_ts) - api.safe_timestamptz(e.field_start_ts)))) / 3600, 2) AS hours, ROUND(SUM(COALESCE(api.safe_bigint(e.field_kills), 0))::numeric / NULLIF(SUM(EXTRACT(EPOCH FROM (api.safe_timestamptz(e.field_end_ts) - api.safe_timestamptz(e.field_start_ts)))) / 3600, 0), 2) AS kills_per_hour FROM api.query_statistics_history_expeditions e WHERE api.safe_timestamptz(e.field_start_ts) IS NOT NULL GROUP BY date_trunc('week', api.safe_timestamptz(e.field_start_ts))::date;
DROP VIEW IF EXISTS api.vw_reserve_performance CASCADE;
CREATE VIEW api.vw_reserve_performance AS SELECT COALESCE(NULLIF(r.field_name, ''), e.field_reserve, 'Unknown') AS reserve_name, e.field_reserve AS reserve_id_raw, COUNT(*) AS expeditions, SUM(COALESCE(api.safe_bigint(e.field_kills), 0)) AS kills, SUM(COALESCE(api.safe_bigint(e.field_collectables), 0)) AS collectables, ROUND(SUM(EXTRACT(EPOCH FROM (api.safe_timestamptz(e.field_end_ts) - api.safe_timestamptz(e.field_start_ts)))) / 3600, 2) AS hours, ROUND(SUM(COALESCE(api.safe_bigint(e.field_kills), 0))::numeric / NULLIF(COUNT(*), 0), 2) AS kills_per_expedition, ROUND(SUM(COALESCE(api.safe_bigint(e.field_kills), 0))::numeric / NULLIF(SUM(EXTRACT(EPOCH FROM (api.safe_timestamptz(e.field_end_ts) - api.safe_timestamptz(e.field_start_ts)))) / 3600, 0), 2) AS kills_per_hour, MIN(api.safe_timestamptz(e.field_start_ts)) AS first_seen_at, MAX(api.safe_timestamptz(e.field_start_ts)) AS last_seen_at FROM api.query_statistics_history_expeditions e LEFT JOIN api.query_catalog_reserves r ON r.field_id = e.field_reserve WHERE api.safe_timestamptz(e.field_start_ts) IS NOT NULL GROUP BY COALESCE(NULLIF(r.field_name, ''), e.field_reserve, 'Unknown'), e.field_reserve;
DROP VIEW IF EXISTS api.vw_personal_records CASCADE;
CREATE VIEW api.vw_personal_records AS SELECT b.record_id AS source_record_id, b.parent_record_id, api.safe_bigint(b.field_specie) AS species_id, COALESCE(NULLIF(s.field_name, ''), 'Species ID ' || b.field_specie) AS species_name, 'distance' AS record_type, api.safe_bigint(b.field_distance_field_animal_id) AS animal_id, api.safe_numeric(b.field_distance_field_score) AS score, api.safe_numeric(b.field_distance_field_distance) AS distance, api.safe_bigint(b.field_distance_field_weapon_id) AS weapon_id, COALESCE(NULLIF(i.field_name, ''), 'Weapon ' || b.field_distance_field_weapon_id) AS weapon_name, api.safe_timestamptz(b.field_distance_field_confirm_ts) AS confirm_at, b.field_distance_field_gender AS gender, b.field_distance_field_texture AS texture FROM api.query_statistics_best_data b LEFT JOIN api.query_catalog_species s ON api.safe_bigint(s.field_id) = api.safe_bigint(b.field_specie) LEFT JOIN api.query_catalog_items i ON api.safe_bigint(i.field_id) = api.safe_bigint(b.field_distance_field_weapon_id) WHERE b.field_distance_field_animal_id IS NOT NULL UNION ALL SELECT b.record_id AS source_record_id, b.parent_record_id, api.safe_bigint(b.field_specie) AS species_id, COALESCE(NULLIF(s.field_name, ''), 'Species ID ' || b.field_specie) AS species_name, 'score' AS record_type, api.safe_bigint(b.field_score_field_animal_id) AS animal_id, api.safe_numeric(b.field_score_field_score) AS score, api.safe_numeric(b.field_score_field_distance) AS distance, api.safe_bigint(b.field_score_field_weapon_id) AS weapon_id, COALESCE(NULLIF(i.field_name, ''), 'Weapon ' || b.field_score_field_weapon_id) AS weapon_name, api.safe_timestamptz(b.field_score_field_confirm_ts) AS confirm_at, b.field_score_field_gender AS gender, b.field_score_field_texture AS texture FROM api.query_statistics_best_data b LEFT JOIN api.query_catalog_species s ON api.safe_bigint(s.field_id) = api.safe_bigint(b.field_specie) LEFT JOIN api.query_catalog_items i ON api.safe_bigint(i.field_id) = api.safe_bigint(b.field_score_field_weapon_id) WHERE b.field_score_field_animal_id IS NOT NULL;
DROP VIEW IF EXISTS api.vw_leaderboard_top100 CASCADE;
CREATE VIEW api.vw_leaderboard_top100 AS SELECT 'score' AS leaderboard_type, api.safe_bigint(p.field_id) AS species_id, COALESCE(NULLIF(p.field_name, ''), NULLIF(s.field_name, ''), 'Species ID ' || p.field_id) AS species_name, api.species_icon_url(COALESCE(NULLIF(p.field_name, ''), NULLIF(s.field_name, ''), 'Species ID ' || p.field_id)) AS animal_icon_url, api.medal_icon_url(api.safe_bigint(r.field_rank)) AS medal_icon_url, api.safe_bigint(r.field_animal_id) AS animal_id, api.animal_profile_url(r.field_user_field_handle, api.safe_bigint(r.field_animal_id)) AS animal_profile_url, api.safe_bigint(r.field_rank) AS rank_no, api.safe_numeric(r.field_score) AS score, r.field_scoretype AS score_type, r.field_user_field_id AS user_id, r.field_user_field_handle AS handle, r.field_user_field_avatar AS avatar_url FROM api.query_leaderboards_score_records r LEFT JOIN api.query_leaderboards_score p ON p.record_id = r.parent_record_id LEFT JOIN api.query_catalog_species s ON api.safe_bigint(s.field_id) = api.safe_bigint(p.field_id) UNION ALL SELECT 'range' AS leaderboard_type, api.safe_bigint(p.field_id) AS species_id, COALESCE(NULLIF(p.field_name, ''), NULLIF(s.field_name, ''), 'Species ID ' || p.field_id) AS species_name, api.species_icon_url(COALESCE(NULLIF(p.field_name, ''), NULLIF(s.field_name, ''), 'Species ID ' || p.field_id)) AS animal_icon_url, api.medal_icon_url(api.safe_bigint(r.field_rank)) AS medal_icon_url, api.safe_bigint(r.field_animal_id) AS animal_id, api.animal_profile_url(r.field_user_field_handle, api.safe_bigint(r.field_animal_id)) AS animal_profile_url, api.safe_bigint(r.field_rank) AS rank_no, api.safe_numeric(r.field_score) AS score, r.field_scoretype AS score_type, r.field_user_field_id AS user_id, r.field_user_field_handle AS handle, r.field_user_field_avatar AS avatar_url FROM api.query_leaderboards_range_records r LEFT JOIN api.query_leaderboards_range p ON p.record_id = r.parent_record_id LEFT JOIN api.query_catalog_species s ON api.safe_bigint(s.field_id) = api.safe_bigint(p.field_id);

